INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a1f10900-0000-4000-8000-000000000000','a1f00000-0000-4000-8000-000000000000','確認テスト ─ 主任が知らないとまずい労基法の基本','quiz',NULL,NULL,NULL,3,2),
  ('a1f20900-0000-4000-8000-000000000000','a1f00000-0000-4000-8000-000000000000','確認テスト ─ ハラスメント予防','quiz',NULL,NULL,NULL,3,4)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a1f10900-0000-4000-8000-000000000000','台本が示す、労働基準法の本質を一行で言うと何か。','働く人を守るための、最低ラインの約束','会社の成長を支えるための、経営の指針','労使が対等に交渉するための、取引のルール','優れた職場をつくるための、理想の基準','A',0),
('a1f10900-0000-4000-8000-000000000000','台本によれば、部下が「自分は残業代いりません」と言った場合、労基法の「最低ライン」はどう扱われるか。','本人の同意があれば、その分だけ下回ってよい','本人の同意があっても、原則、下回れない','上司が承認すれば、床を取り払える','就業規則に明記すれば、下げられる','B',1),
('a1f10900-0000-4000-8000-000000000000','台本が「いちばん危ない」とする、板挟みから最も重い違反に踏み込む例はどれか。','有給の申請に「理由は?」と問い返す','昼休みを取らない部下を頼もしいと黙認する','「タイムカードは定時で、あとはサービスで」と記録を改ざんする','「今日だけ、もう少し」と残業を頼む','C',2),
('a1f20900-0000-4000-8000-000000000000','台本が示す、ハラスメントの本質を一行で言うと何か。','相手より強い口調で、感情的に叱ること','力の使い方を誤り、相手の尊厳を傷つけること','部下の成長を願わず、指導を放棄すること','職場のルールを、一方的に押しつけること','B',0),
('a1f20900-0000-4000-8000-000000000000','台本によれば、指導とハラスメントを分ける「対象」の基準はどれか。','声を荒げているか、穏やかに話しているか','相手が年上か、年下か','相手の「行動」を扱うか、「人格」を裁くか','一度きりか、繰り返しているか','C',1),
('a1f20900-0000-4000-8000-000000000000','台本が示す、部下からハラスメントの相談を受けたときの初動として正しいのはどれか。','「気にしすぎじゃない?」とまず落ち着かせる','主任が一人で責任を持って解決にあたる','事実か解釈かを、その場で主任が判断する','否定せずまず聴き、事実を記録し、抱え込まず窓口へつなぐ','D',2);
